const data = $json.data || [];
const paginas = data.map(p => ({
  page_id: p.id,
  page_name: p.name,
  category: p.category || 'N/A',
  instagram_business_account_id: p.instagram_business_account
    ? p.instagram_business_account.id
    : 'NAO_ENCONTRADO'
}));

if (paginas.length === 0) {
  return { json: {
    erro: 'Nenhuma pagina encontrada. Verifique a credencial Aplicativo do Facebook.',
    paginas: [],
    page_id_principal: 'NAO_ENCONTRADO',
    page_name_principal: 'NAO_ENCONTRADO',
    instagram_business_account_id: 'NAO_ENCONTRADO',
    total_paginas: 0
  }};
}

return {
  json: {
    total_paginas: paginas.length,
    paginas,
    page_id_principal: paginas[0].page_id,
    page_name_principal: paginas[0].page_name,
    instagram_business_account_id: paginas[0].instagram_business_account_id
  }
};
